  ('judicial-cf446b4c-moex-00094', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲要射殺數公尺外的乙，但是因為槍法失準，射中距離乙數公尺的丙，致丙死亡。下列敘述何者正確？', '["本案事實屬打擊錯誤", "本案事實屬客體錯誤", "本案事實屬容許構成要件錯誤", "本案事實屬禁止錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00095', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲持刀欲殺乙，經乙呼救，甲因害怕遂持刀逃往鄰家，驚動四鄰後，甲始棄刀向警自首。有關甲之刑責， 下列何者正確？', '["甲構成準中止未遂", "甲構成中止未遂", "甲構成障礙未遂", "甲構成不能未遂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00096', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依實務見解對於著手時點之認定，下列何者可認為是竊盜犯行之著手階段？', '["甲基於竊盜財物之目的而破壞乙公司的門扇，欲侵入公司之內", "甲基於竊盜財物之目的而侵入乙公司內，接近並物色乙公司的財物，但尚未實際破壞乙公司對財物的持 有關係", "甲為侵入乙公司內竊盜財物，早一日先至乙公司附近勘查地形", "甲為侵入乙公司內竊盜財物，先行破壞乙公司之保全系統，以利入侵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00097', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依實務見解，關於共同正犯的既未遂與脫離關係之認定，下列何者正確？', '["必須要共同正犯之全體成員均達既遂階段，始能肯定共同正犯的既遂", "一旦加入共同正犯，即負共同責任，不生脫離的可能性", "若要脫離共同正犯，則除了放棄自己的行為並使未脫離者了解該情形外，也必須切斷自己先前所創造的 因果關係", "共同正犯脫離後，沒有另外成立中止犯的空間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00098', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於我國刑法對於正犯與共犯之概念，下列敘述何者正確？', '["係採單一正犯概念", "係採共犯獨立性概念", "係採區分正共犯概念", "並無共犯之獨立規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00099', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲、乙共謀前往A宅竊盜，A宅鄰居丙聽到，決定暗助甲、乙兩人，於是當天晚上故意在A宅旁放梯子， 甲、乙即直接使用該梯子翻入A宅行竊得手。丙之刑責為何？', '["加重竊盜罪之共同正犯", "加重竊盜罪之教唆犯", "加重竊盜罪之幫助犯", "加重竊盜罪之間接正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00100', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲因犯罪被起訴，甲之律師丙於是和證人乙商討，希望證人乙在法庭上作偽證說甲不在犯罪現場，乙果依 丙之要求而作偽證。丙成立何罪？', '["偽證罪的教唆犯", "偽證罪之正犯", "偽證罪之間接正犯", "偽證罪之共同正犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00101', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法之沒收，下列何者正確？', '["沒收只能對犯罪人行之，對第三人不能沒收", "犯罪所得屬於義務沒收之類型", "犯罪所得之沒收不以違法行為為前提", "只有犯罪人擁有所有權的犯罪所得，才是沒收的對象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00102', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種情形不可以追徵犯罪所得之價額？', '["全部不能沒收", "一部不能沒收", "不宜執行沒收", "犯罪所得已實際合法發還被害人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00103', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲見乙當街對丙為強盜行為，乙奪取財物後欲離開現場，甲上前欲逮捕乙，竟遭乙毆打，甲腿部扭傷倒地 不起，乙遂持贓物離開現場。有關乙之行為，下列敘述何者正確？', '["乙對丙成立強盜既遂罪，對甲成立普通傷害罪，兩罪數罪併罰", "乙對丙成立強盜既遂罪，對甲成立普通傷害罪，兩罪想像競合", "乙對丙成立強盜既遂罪，對甲成立準強盜罪，兩罪數罪併罰", "乙對丙成立強盜既遂罪，對甲成立準強盜罪，兩罪想像競合"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
